90	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
91	
92	const componentGroupBase = (count: number, unitBase: number): number => {
93	  if (count === BLOCK_SIZE) return BLOCK_BASE;
94	  return count * unitBase;
95	};
