97	const itemSurchargeRate = (item: Item): number => {
98	  let rate = 0;
99	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
100	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
101	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
102	  }
103	  return rate;
104	};
