109	const policyModifierRate = (customer: Customer, quoteIndex: number): number => {
110	  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
111	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
112	    rate -= LOYALTY_DISCOUNT_RATE;
113	  }
114	  if (quoteIndex >= 1) {
115	    rate -= FOLLOWUP_DISCOUNT_RATE;
116	  }
117	  return rate;
118	};
