120	const quotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
121	  let policyBase = 0;
122	  let itemSurchargeTotal = 0;
123	  const componentCounts = new Map<string, number>();
124	
125	  for (const item of items) {
126	    if (COMPONENT_TYPES.has(item.type)) {
127	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
128	    } else {
129	      const base = itemBase(item.type);
130	      policyBase += base;
131	      itemSurchargeTotal += itemSurcharge(item, base);
132	    }
133	  }
134	
135	  for (const [type, count] of componentCounts) {
136	    const groupBase = componentGroupBase(count, itemBase(type));
137	    policyBase += groupBase;
138	  }
139	
140	  const policyModifierTotal = policyBase * policyModifierRate(customer, quoteIndex);
141	  const total = policyBase + itemSurchargeTotal + policyModifierTotal;
142	  return roundUp(total) + PROCESSING_FEE;
143	};
